mapper.select:
SELECT cqr.* FROM chapter_quiz_results cqr
INNER JOIN chapters c ON cqr.chapter_id = c.id
WHERE cqr.user_id = #{userId} AND c.course_id = #{courseId}

mapper.update:
UPDATE chapter_quiz_results
total_score = #{totalScore}, max_score = #{maxScore}, correct_count = #{correctCount}, total_count = #{totalCount}, attempt_count = #{attemptCount}, is_passed = #{isPassed}, submitted_at = NOW()
WHERE id = #{id}

mapper.select:
SELECT COALESCE(AVG(cqr.total_score), 0) FROM chapter_quiz_results cqr
INNER JOIN chapters c ON cqr.chapter_id = c.id
WHERE cqr.user_id = #{userId} AND c.course_id = #{courseId}
